  1→package dashboard
  2→
  3→import (
  4→	"fmt"
  5→	"strings"
  6→	"time"
  7→
  8→	"github.com/charmbracelet/lipgloss"
  9→
 10→	"github.com/jcleira/entire-local/pkg/checkpoint"
 11→)
 12→
 13→func renderCheckpointList(summaries []checkpoint.CheckpointSummary, cursor, height int, filter string, width int) string {
 14→	filtered := filterSummaries(summaries, filter)
 15→
 16→	var sb strings.Builder
 17→
 18→	header := headerStyle.Render("Checkpoints")
 19→	if filter != "" {
 20→		header += " " + filterStyle.Render("[/"+filter+"]")
 21→	}
 22→	header += dimStyle.Render(fmt.Sprintf(" (%d)", len(filtered)))
 23→	sb.WriteString(header)
 24→	sb.WriteString("\n")
 25→
 26→	if len(filtered) == 0 {
 27→		sb.WriteString(dimStyle.Render("  No checkpoints found"))
 28→		return sb.String()
 29→	}
 30→
 31→	visibleHeight := (height - 2) / 3
 32→	if visibleHeight < 1 {
 33→		visibleHeight = 1
 34→	}
 35→
 36→	start := 0
 37→	if cursor >= visibleHeight {
 38→		start = cursor - visibleHeight + 1
 39→	}
 40→	end := start + visibleHeight
 41→	if end > len(filtered) {
 42→		end = len(filtered)
 43→	}
 44→
 45→	contentWidth := width - 4
 46→	if contentWidth < 40 {
 47→		contentWidth = 40
 48→	}
 49→
 50→	for i := start; i < end; i++ {
 51→		s := filtered[i]
 52→		block := renderCheckpointBlock(s, contentWidth)
 53→
 54→		if i == cursor {
 55→			sb.WriteString(selectedRowStyle.Render(block))
 56→		} else {
 57→			sb.WriteString(normalRowStyle.Render(block))
 58→		}
 59→		sb.WriteString("\n")
 60→	}
 61→
 62→	if len(filtered) > visibleHeight {
 63→		sb.WriteString(scrollIndicatorStyle.Render(fmt.Sprintf("  (%d/%d)", cursor+1, len(filtered))))
 64→	}
 65→
 66→	return sb.String()
 67→}
 68→
 69→func renderCheckpointBlock(s checkpoint.CheckpointSummary, width int) string {
 70→	sep := dimStyle.Render("  ·  ")
 71→
 72→	title := s.Prompt
 73→	if title == "" {
 74→		title = s.Context
 75→	}
 76→	if title == "" {
 77→		title = s.Branch
 78→	}
 79→	if idx := strings.IndexByte(title, '\n'); idx >= 0 {
 80→		title = title[:idx]
 81→	}
 82→	title = strings.TrimSpace(title)
 83→	if len(title) > width {
 84→		title = title[:width-1] + "…"
 85→	}
 86→	line1 := lipgloss.NewStyle().Bold(true).Render(title)
 87→
 88→	var leftParts []string
 89→	leftParts = append(leftParts, hashStyle.Render(truncateHash(s.CommitHash)))
 90→	leftParts = append(leftParts, dimStyle.Render(formatTimeAgo(s.CreatedAt)))
 91→	if s.Agent != "" {
 92→		leftParts = append(leftParts, agentBadgeStyle.Render(truncate(s.Agent, 16)))
 93→	}
 94→	leftSide := strings.Join(leftParts, sep)
 95→
 96→	var rightParts []string
 97→	if s.Additions > 0 || s.Deletions > 0 {
 98→		rightParts = append(rightParts,
 99→			addStyle.Render(fmt.Sprintf("+%d", s.Additions))+" / "+
100→				delStyle.Render(fmt.Sprintf("-%d", s.Deletions)))
101→	}
102→	if s.FileCount > 0 {
103→		rightParts = append(rightParts, dimStyle.Render(fmt.Sprintf("%d files", s.FileCount)))
104→	}
105→	if s.TotalTokens > 0 {
106→		rightParts = append(rightParts, dimStyle.Render(formatTokensShort(s.TotalTokens)))
107→	}
108→	rightSide := strings.Join(rightParts, sep)
109→
110→	line2 := leftSide
111→	if rightSide != "" {
112→		padding := width - lipgloss.Width(leftSide) - lipgloss.Width(rightSide)
113→		if padding < 2 {
114→			padding = 2
115→		}
116→		line2 = leftSide + strings.Repeat(" ", padding) + rightSide
117→	}
118→
119→	return line1 + "\n" + line2
120→}
121→
122→func filterSummaries(summaries []checkpoint.CheckpointSummary, filter string) []checkpoint.CheckpointSummary {
123→	if filter == "" {
124→		return summaries
125→	}
126→
127→	f := strings.ToLower(filter)
128→	var result []checkpoint.CheckpointSummary
129→	for i := range summaries {
130→		if strings.Contains(strings.ToLower(summaries[i].Branch), f) ||
131→			strings.Contains(strings.ToLower(summaries[i].Agent), f) ||
132→			strings.Contains(strings.ToLower(summaries[i].Prompt), f) ||
133→			strings.Contains(strings.ToLower(summaries[i].Context), f) ||
134→			strings.Contains(strings.ToLower(summaries[i].CommitHash), f) {
135→			result = append(result, summaries[i])
136→		}
137→	}
138→	return result
139→}
140→
141→func formatTimeAgo(t time.Time) string {
142→	if t.IsZero() {
143→		return "unknown"
144→	}
145→	d := time.Since(t)
146→	switch {
147→	case d < time.Minute:
148→		return "just now"
149→	case d < time.Hour:
150→		m := int(d.Minutes())
151→		return fmt.Sprintf("%dm ago", m)
152→	case d < 24*time.Hour:
153→		h := int(d.Hours())
154→		return fmt.Sprintf("%dh ago", h)
155→	default:
156→		days := int(d.Hours() / 24)
157→		return fmt.Sprintf("%dd ago", days)
158→	}
159→}
160→
161→func formatNumber(n int) string {
162→	if n >= 1000 {
163→		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
164→	}
165→	return fmt.Sprintf("%d", n)
166→}
167→
168→func formatTokensShort(n int) string {
169→	if n >= 1000 {
170→		return fmt.Sprintf("%.1fk tokens", float64(n)/1000)
171→	}
172→	return fmt.Sprintf("%d tokens", n)
173→}
174→
175→func truncate(s string, maxLen int) string {
176→	if len(s) <= maxLen {
177→		return s
178→	}
