type Reader struct {
	repoRoot string
}

func NewReader(repoRoot string) *Reader {
	return &Reader{repoRoot: repoRoot}
}

func (r *Reader) ListShards() ([]string, error) {
	out, err := ExecGit(r.repoRoot, "ls-tree", "--name-only", CheckpointBranch)
	if err != nil {
		return nil, err
	}
	if out == "" {
		return nil, nil
	}
	return strings.Split(out, "\n"), nil
}

