	out, err := ExecGit(r.repoRoot, "ls-tree", "--name-only", CheckpointBranch+":"+shard)
	if err != nil {
		return nil, err
	}
	if out == "" {
		return nil, nil
	}
	return strings.Split(out, "\n"), nil
}

func (r *Reader) ReadFile(path string) (string, error) {
	return ExecGit(r.repoRoot, "show", CheckpointBranch+":"+path)
}

